250→/**
251→ * Updates or inserts a new whitespace element with [text] before the given node. If the node itself is a whitespace
252→ * then its contents is replaced with [text]. If the node is a (nested) composite element, the whitespace element is
253→ * added after the previous leaf node.
254→ */
255→public fun ASTNode.upsertWhitespaceBeforeMe(text: String) {
256→    if (this is LeafElement) {
257→        if (this.elementType == WHITE_SPACE) {
258→            return replaceWhitespaceWith(text)
259→        }
260→        val previous = treePrev ?: prevLeaf()
261→        if (previous != null && previous.elementType == WHITE_SPACE) {
262→            previous.replaceWhitespaceWith(text)
263→        } else {
264→            PsiWhiteSpaceImpl(text).also { psiWhiteSpace ->
265→                (psi as LeafElement).rawInsertBeforeMe(psiWhiteSpace)
266→            }
267→        }
268→    } else {
269→        val prevLeaf =
270→            requireNotNull(prevLeaf()) {
271→                "Can not upsert a whitespace if the first node is a non-leaf node"
272→            }
273→        prevLeaf.upsertWhitespaceAfterMe(text)
274→    }
275→}
276→
277→private fun ASTNode.replaceWhitespaceWith(text: String) {
278→    require(this.elementType == WHITE_SPACE)
279→    if (this.text != text) {
280→        (this.psi as LeafElement).rawReplaceWithText(text)
281→    }
282→}
