284→/**
285→ * Updates or inserts a new whitespace element with [text] after the given node. If the node itself is a whitespace
286→ * then its contents is replaced with [text]. If the node is a (nested) composite element, the whitespace element is
287→ * added after the last child leaf.
288→ */
289→public fun ASTNode.upsertWhitespaceAfterMe(text: String) {
290→    if (this is LeafElement) {
291→        if (this.elementType == WHITE_SPACE) {
292→            return replaceWhitespaceWith(text)
293→        }
294→        val next = treeNext ?: nextLeaf()
295→        if (next != null && next.elementType == WHITE_SPACE) {
296→            next.replaceWhitespaceWith(text)
297→        } else {
298→            PsiWhiteSpaceImpl(text).also { psiWhiteSpace ->
299→                (psi as LeafElement).rawInsertAfterMe(psiWhiteSpace)
300→            }
301→        }
302→    } else {
303→        lastChildLeafOrSelf().upsertWhitespaceAfterMe(text)
304→    }
305→}
