import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class CommentWrappingRuleFixTest {
    private val commentWrappingRuleAssertThat = assertThatRule { CommentWrappingRule() }

    @Test
    fun `Given a block comment inside a single line lambda then do not reformat`() {
        val code =
            """
            val foo = { /* no-op */ }
            """.trimIndent()
        commentWrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a block comment inside a single line block then do not reformat`() {
        val code =
            """
            fun bar() { /* no-op */ }
            """.trimIndent()
        commentWrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a block comment inside a multiline lambda then do reformat`() {
        val code =
            """
            val foo = {
                /* no-op */
            }
            """.trimIndent()
        commentWrappingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a block comment inside a multiline block then do reformat`() {
        val code =
            """
            fun bar() {
                /* no-op */
            }
            """.trimIndent()
        commentWrappingRuleAssertThat(code).hasNoLintViolations()
    }
